mapper.select:
/* 포인트: 회원 행 잠금 */
SELECT USR_SN
FROM USERS
WHERE USR_SN = #{usrSn}
FOR UPDATE

/* 포인트: 참조 건별 유효 홀딩 금액 */
SELECT COALESCE(SUM(PT_LDG_AMT), 0)
FROM POINT_LEDGER
WHERE USR_SN = #{usrSn}
  AND PT_LDG_PT_TYPE_CD = 'PTLC0002'
  AND PT_LDG_REF_TYPE_CD = #{refTypeCd}
  AND PT_LDG_REF_SN = #{refSn}

mapper.insert:
/* 포인트: 원장 행 추가 */
INSERT INTO POINT_LEDGER (
    USR_SN, ACTOR_USR_SN,
    PT_LDG_REF_TYPE_CD, PT_LDG_REF_SN,
    PT_LDG_PT_TYPE_CD, PT_LDG_TYPE_CD,
    PT_LDG_AMT, PT_LDG_BAL_AFTER_AMT, PT_LDG_RSN_CN
) VALUES (
    #{usrSn}, #{actorUsrSn},
    #{ptLdgRefTypeCd}, #{ptLdgRefSn},
    #{ptLdgPtTypeCd}, #{ptLdgTypeCd},
    #{ptLdgAmt}, #{ptLdgBalAfterAmt}, #{ptLdgRsnCn}
)
